select *
from batch.trigger_request
where tenant_id = #{tenantId}

    and job_code = #{jobCode}


    and trigger_type = #{triggerType}


    and request_status = #{requestStatus}

order by id desc

select *
from batch.trigger_request
where tenant_id = #{tenantId}
  and request_id = #{requestId}

select *
from batch.trigger_request
where tenant_id = #{tenantId}
  and dedup_key = #{dedupKey}

mapper.insert:
insert into batch.trigger_request ( tenant_id, request_id, trigger_type, job_code, biz_date, dedup_key, request_status, trace_id, dry_run ) values ( #{tenantId}, #{requestId}, #{triggerType}, #{jobCode}, #{bizDate}, #{dedupKey}, #{requestStatus}, #{traceId},
#{dryRun} false
)

mapper.update:
update batch.trigger_request
set request_status = #{requestStatus},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and request_id = #{requestId}

update batch.trigger_request
set request_status = #{requestStatus},
    updated_at     = current_timestamp
where tenant_id      = #{tenantId}
  and request_id     = #{requestId}
  and request_status = #{expectedStatus}

update batch.trigger_request
set related_job_instance_id = #{relatedJobInstanceId},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and request_id = #{requestId}
